fn dotProduct(a: []const f32, b: []const f32) f32 {
    const Vec4 = @Vector(4, f32);
    var sum: Vec4 = @splat(0);

    const len = @min(a.len, b.len);
    const vec_len = len / 4 * 4;

    var i: usize = 0;
    while (i < vec_len) : (i += 4) {
        const va: Vec4 = a[i..][0..4].*;
        const vb: Vec4 = b[i..][0..4].*;
        sum += va * vb;
    }

    var result = @reduce(.Add, sum);
    while (i < len) : (i += 1) {
        result += a[i] * b[i];
    }
    return result;
}

fn normalize(v: []f32) void {
    const len_sq = dotProduct(v, v);
    if (len_sq == 0) return;

    const inv_len = 1.0 / @sqrt(len_sq);
    const Vec4 = @Vector(4, f32);
    const scale: Vec4 = @splat(inv_len);

    var i: usize = 0;
    while (i + 4 <= v.len) : (i += 4) {
        const vec: Vec4 = v[i..][0..4].*;
        v[i..][0..4].* = vec * scale;
    }
    while (i < v.len) : (i += 1) {
        v[i] *= inv_len;
    }
}
